var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그 많은 침식체들이 단번에…….","JPN":"あんなにたくさんいた侵食体を一気に……","ENG":"All those C.O.s wiped out in an instant...","TWN":"那麼多侵蝕體一下就……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"일어날 수 있겠나?","JPN":"立てるか？","ENG":"Can you stand up?","TWN":"妳還能站起來嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"덕분에 무사히 격납고를 지킬 수 있었습니다.","JPN":"おかげさまで、無事格納庫を守ることができました。","ENG":"Thanks to you, the hangar is safe.","TWN":"多虧你們，我們才能平安守住機庫。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"……인상착의를 보아하니 지난번 거대한 고래형 침식체를 토벌한 카운터로군요.","JPN":"……その姿、以前クジラ型の巨大侵食体を討伐したカウンターですね。","ENG":"...Judging from appearances, you must be the Counter who brought down that massive whale-type C.O. last time.","TWN":"……看你的服裝，應該就是上次討伐巨大鯨魚型侵蝕體的那位制裁者吧。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"로터스 어딘가에서 가이드를 하고 있단 소식까지는 접했습니다만.","JPN":"ロータスのどこかでガイドの仕事をしているという話は聞きましたが。","ENG":"I had only heard rumors you were guiding somewhere in Lotus.","TWN":"我只聽說你在洛德斯的某處擔任嚮導。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"오, 거기까지 알고 있었나? 그럼 정식으로 소개하지.","JPN":"お、そこまで知っているのか？　では正式に自己紹介しよう。","ENG":"Oh? You knew that much? Then allow me to introduce myself properly.","TWN":"哦，妳連那個都知道啊？那我正式自我介紹一下吧。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"클라이언트를 실망시키지 않는 즐거움. 바루나 투어의 수리야다.","JPN":"クライアントをがっかりさせない楽しさ。ヴァルナツアーのスーリヤだ。","ENG":"The joy of never disappointing a client. I am Surya of Varuna Tours.","TWN":"我是不辜負客戶期望的樂趣，伐樓拿旅行社的蘇莉耶。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L17_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"바루나 투어 어플을 통해 가이드 별점 5점을 부탁하지.","JPN":"ヴァルナツアーアプリでガイド評価に★5つを頼む。","ENG":"Be sure to give us a five-star rating on the Varuna Tour app.","TWN":"請務必透過伐樓拿旅遊APP給我5星好評。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"실례지만, 인상에 썩 어울리는 자기소개는 아닌 것 같습니다.","JPN":"恐れ入りますが、印象に見合った自己紹介ではない気がします。","ENG":"Forgive me, but that self-introduction does not quite suit your image.","TWN":"不好意思，這種自我介紹跟妳給人的第一印象完全不搭。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"미, 미안하군.","JPN":"す、すまない。","ENG":"I-I'm sorry.","TWN":"不、不好意思。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"우리 대표가 사람을 만나면 항상 이렇게 말하라고 해서 습관이 되어버리는 바람에…….","JPN":"初対面の人には必ずこう言うようにと、代表に言われているので、つい……","ENG":"My boss insisted we say that whenever we meet people, and it became habit...","TWN":"我們代表叫我們每次見到人都要這樣說，結果變成習慣了……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"……생각보다 훨씬 재밌으신 분이군요.","JPN":"……思ったより面白い方ですね。","ENG":"...You are far more entertaining than I expected.","TWN":"……看來妳比我想像了還有趣呢。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"로터스 관리국의 경호국장, 파티마입니다.","JPN":"私はロータス管理局の警護局長、ファティマです。","ENG":"I am Fatima, Chief of Lotus Administration's security.","TWN":"我是洛德斯管理局的警護局局長，法蒂瑪。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"직할 도시에서 불어온 바람이 심상치 않았는데, 무사해서 다행이에요.","JPN":"直轄都市から吹いて来た風にただならぬ気配を感じてましたが、ご無事でなによりです。","ENG":"The wind blowing from the Direct Control City carried a strange feeling. I'm glad you are safe.","TWN":"從直轄城市吹來的風不太尋常，還好都沒事。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"네가 수상한 기운을 감지한 덕분이다. 아닐라.","JPN":"君がその気配に気づいてくれたおかげだ、アニラ。","ENG":"Thanks to your sensing that suspicious energy, Anila.","TWN":"這都是多虧妳察覺到可疑的氣息啊，雅妮拉。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"어디 다친 곳은 없나?","JPN":"怪我はないか？","ENG":"Are you hurt anywhere?","TWN":"妳有沒有哪裡受傷？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"저는 괜찮습니다.","JPN":"私は大丈夫です。","ENG":"I'm fine.","TWN":"我沒事。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"격납고로 침입하려는 침식체들도 제가 날려버렸으니, 당분간은 잠잠할 거예요.","JPN":"格納庫に侵入しようとした侵食体も全部吹き飛ばしましたし、しばらくは問題ないと思います。","ENG":"I swept away the C.O.s trying to break into the hangar, so it should be quiet for a while.","TWN":"我也把那些試圖侵入機庫的侵蝕體吹走了，短期內應該不會再鬧事。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"저, 저기…….","JPN":"あ、あの……","ENG":"Um... excuse me...","TWN":"那、那個……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"당신들이 파티마를 도와서 이 격납고를 지켜준 거야?","JPN":"あなたたちが、ファティマを手伝ってこの格納庫を守ってくれたの？","ENG":"You are the ones who helped Fatima defend this hangar?","TWN":"是你們幫法蒂瑪守住這個機庫的嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"클라이언트를 실… 그렇다.","JPN":"クライアントをがっ……そうだ。","ENG":"The joy of never disappo– Yes.","TWN":"不辜負客戶期……是的。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"고마워. 당신들이 아니었으면 파티마 혼자선 버거웠을 거야.","JPN":"ありがとう。2人が来てくれなかったら、ファティマ1人では厳しかったと思うの。","ENG":"Thank you. Fatima would've struggled on her own.","TWN":"謝謝你們。如果沒有你們幫忙，法蒂瑪一個人會很吃力。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"당신들이 와준 덕분에 새어 나가는 침식체 없이 정리할 수 있었습니다.","JPN":"皆さんが来てくださったおかげで、1匹残らず侵食体を片付けられました。","ENG":"With your help, we managed to contain the C.O.s without a single breach.","TWN":"多虧你們來了，我們才能徹底殲滅侵蝕體，沒有漏網之魚。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"경호국장이 여태까지 침식체들을 막아준 덕분에 우리도 남은 침식체들을 정화할 수 있었다.","JPN":"警護局長が今まで侵食体を止めてくれていたから、私たちも残党を浄化できたのだ。","ENG":"It was the Chief of Security who held the line until now. We merely came in at the end to purify the rest.","TWN":"這都是因為警護局長一直在阻擋侵蝕體，我們才能進行最後的淨化。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"나는 그저 숟가락만 얹은 셈이니, 이 이상의 칭찬을 받는 것도 부담스럽군.","JPN":"少し力を貸したぐらいで、これ以上褒められると困ってしまうな。","ENG":"I only played a small part, so any more praise would be undeserved.","TWN":"我只是來插一腳而已，這麼稱讚我反而讓我覺得不好意思。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그리고… 지원이 늦은 점에 대해 사과하겠다.","JPN":"そして……支援が遅れたこと、すまない。","ENG":"And... I apologize for arriving so late.","TWN":"還有……很抱歉我們來得太晚了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아냐, 당신들은 소집 명령에 응할 의무가 없었잖아.","JPN":"ううん、あなたたちは招集命令に応じる義務もないじゃない。","ENG":"No, you weren't even obligated to answer the call.","TWN":"沒關係，你們本來就沒有義務服從召集命令。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"여행 가이드 회사에 당신들 같은 강자가 있는 줄 알았으면 진작 불렀을 텐데…….","JPN":"旅行ガイドの会社にあなたたちのように強い人がいるって知ってたら、最初から声をかけてたのに……","ENG":"Had I known a tour company had fighters like you, I would have called long ago...","TWN":"早知道旅行社裡有像你們一樣這麼厲害的人，我就請你們來了……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아, 혹시 당신들도 최고 관리자가 보낸 사람들이야?","JPN":"あ、もしかして2人も、最高管理者の指示で……？","ENG":"Wait, were you also sent by the Supreme Administrator?","TWN":"啊……你們也是最高管理者派來的嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그래. 예전엔 구 관리국 소속의 바루나 전대라고 불렸지.","JPN":"ああ。昔は旧管理局所属のヴァルナ戦隊と呼ばれていた。","ENG":"Correct. We were once known as Varuna Division of the Old Administration.","TWN":"是啊，我們曾是隸屬舊管理局的伐樓拿戰隊。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"쳇, 그 사람. 도대체 자기 사람을 얼마나 심어 놓은 거야?","JPN":"ちっ、あの人……いったい何人仕込んでるのよ？","ENG":"Tch, just how many people has he planted everywhere?","TWN":"哼，那傢伙到底塞了多少自己的人？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이제는 여행 가이드까지 구 관리국의 사람이라고?","JPN":"よもや旅行ガイドの人まで旧管理局出身？　うそでしょ？","ENG":"Even tour guides are people from the Old Administration now?","TWN":"連導遊都是舊管理局的人嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"당신들은 최고 관리자한테 무슨 명령을 받았어?","JPN":"2人は最高管理者からどんな命令を受けてきたの？","ENG":"What orders did you receive from the Supreme Administrator?","TWN":"你們從最高管理者那裡接到什麼命令？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"최고 관리자님의 명령으로 사막에서 부상한 침식체들을 정화하고 있었습니다.","JPN":"最高管理者様の命令で、砂漠に浮上した侵食体を浄化していました。","ENG":"By his command, we were purifying C.O.s rising in the desert.","TWN":"我們奉最高管理者之命，正在沙漠淨化甦醒的侵蝕體。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"역시…… 사막 쪽도 대균열의 영향을 받았구나.","JPN":"やっぱり……砂漠のほうも大亀裂の影響を受けているんだね。","ENG":"I knew it... Even the desert is under the Grand Dimension Crevice's influence.","TWN":"果然……沙漠那邊也受到大峽谷的影響了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"혹시 다른 재건 도시들 소식 들은 건 없어?","JPN":"他の再建都市について、何か知ってることはない？","ENG":"Have you heard any news from the other reconstruction cities?","TWN":"你們有沒有聽到其他重建城市的消息？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"CSE 레벨이 급격히 상승하는 바람에 일반적인 통신 장비가 먹통이 되어버렸거든.","JPN":"CSEレベルが急激に上がったせいで、普通の通信装備は使えなくなっちゃったの。","ENG":"The CSE level spike disabled most standard comms.","TWN":"因為CSE等級急速上升，一般通訊設備全都失效了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"미안하군. 우리도 사막의 차원 폭풍 속에서 정화를 진행하다 보니 따로 연락을 받은 곳은 없다.","JPN":"悪いな。私たちも砂漠の次元の暴風の中で浄化を行っていたため、これといった連絡は受けていない。","ENG":"Sorry. We were so tied up purifying within the dimensional storms that we heard nothing.","TWN":"抱歉。我們在沙漠的次元風暴中進行淨化，沒收到任何聯絡。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그, 그래… 그럼 어쩔 수 없지.","JPN":"そ、そう……じゃあ仕方ないね。","ENG":"I-I see. Nothing to be done then.","TWN":"這、這樣啊……那也沒辦法。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"파티마. 혹시 알파트릭스 이노베이션과 연락은 됐어?","JPN":"ファティマ。アルファトリックス・イノベーションと連絡は取れた？","ENG":"Fatima, have you managed to contact Alphatrix Innovation?","TWN":"法蒂瑪，妳能聯絡阿爾法崔克斯改革嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그게…….","JPN":"それが……","ENG":"Well...","TWN":"那個……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"상황이 좋지 않아 보이는군.","JPN":"あまり好ましくはない状況だと見たが。","ENG":"Things do not look good.","TWN":"看來情況不太妙呢。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"으, 으앗?!","JPN":"う、うあっ！？","ENG":"H-huh?!","TWN":"呃、呃啊？！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 통신?","JPN":"な、何？　通信？","ENG":"W-what?! A transmission?","TWN":"什、什麼？通訊？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"여긴 침식파가 강해서 전파가 통하지 않는 지역인데 어떻게……?","JPN":"ここは侵食波が強くて電波が届かない地域なのに、どうやって……？","ENG":"But this area's Corruption rays jammed all signals...","TWN":"這裡原本因為強大的侵蝕完全無法收訊，怎麼會……？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"끊임없이 진화하고 극복하는 나에겐 이 정도 침식파는 문제 되지 않는다.","JPN":"絶え間なく進化と克服を続ける私に、この程度の侵食波など何の問題にもならない。","ENG":"For one who constantly evolves and adapts, such rays are nothing.","TWN":"對不斷進化並克服一切的我來說，這點侵蝕波根本不算什麼。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"로터스의 시니어, 네가 넘긴 설계도를 통해 선로전환기 제작을 완료하였다.","JPN":"ロータスのシニア、お前が渡した設計図で線路転換器の製作を完了した。","ENG":"Using the blueprints you provided, we have completed construction of the Track Switcher.","TWN":"洛德斯的Senior啊，多虧你提供的設計圖，線路轉換器已經完成了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"자세한 이야기는 만나서 하도록 하지.","JPN":"詳細は会ってから話すとしよう。","ENG":"We will speak in detail when we meet.","TWN":"細節等見面再談吧。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"마, 만나서라고? 어떻게?","JPN":"あ、会うって、どうやって？","ENG":"M-meet? How?","TWN":"見、見面？要怎麼見？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"곧 그곳에 도착할 것이다.","JPN":"もうすぐそこに着く。","ENG":"I will be arriving there shortly.","TWN":"我很快就會到了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_TOUCH"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_30"},{"id":"L35_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"쓸데없는 행동으로 시간을 낭비하지 말도록.","JPN":"余計な行動で時間を無駄にするな。","ENG":"Do not waste time with useless diversions.","TWN":"別浪費時間在無謂的行動上了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};